+void TrajectoryGenerator::modifyWaypointCallback(
+    const as2_msgs::msg::PoseStampedWithID::SharedPtr _msg) {
+  RCLCPP_DEBUG(this->get_logger(), "Waypoint[%s] to modify has been received",
+               _msg->id.c_str());
